import{_ as a,o as l,c as p,a6 as t,iB as r,iC as s,iD as e,iE as o,iF as n,iG as _,iH as c,iI as m,iJ as g,iK as d,iL as h,iM as x}from"./chunks/framework.UYVGz2W_.js";const D=JSON.parse('{"title":"クライアントプレイリスト","description":"","frontmatter":{},"headers":[],"relativePath":"ja/playlist-client/index.md","filePath":"ja/playlist-client/index.md"}'),f={name:"ja/playlist-client/index.md"};function u(b,i,P,k,T,v){return l(),p("div",null,[...i[0]||(i[0]=[t('<h1 id="クライアントプレイリスト" tabindex="-1">クライアントプレイリスト <a class="header-anchor" href="#クライアントプレイリスト" aria-label="Permalink to “クライアントプレイリスト”">​</a></h1><h2 id="クライアントプレイリストの作成" tabindex="-1">クライアントプレイリストの作成 <a class="header-anchor" href="#クライアントプレイリストの作成" aria-label="Permalink to “クライアントプレイリストの作成”">​</a></h2><p>クライアントとレビューを行うための最初のステップは、共有およびレビューしたいコンテンツのプレイリストを作成することです。このプロセスは通常のプレイリストの作成と似ていますが、Kitsuには、スタジオ外の関係者との共同作業を支援する便利な機能がいくつか含まれています。</p><p>まず、プレイリストを作成し、レビューしたいアイテムを追加します。 作成方法については、このセクションを参照してください（../review#create-a-playlist）。</p><p>主な違いは、「共有先」で「クライアント」を選択することです。これにより、適切な権限が確保され、クライアントにはこの特定のプレイリストへのアクセスのみが提供されます。</p><p><img src="'+r+'" alt="グローバルプレイリスト"></p><h2 id="クライアントプレイリストの確認" tabindex="-1">クライアントプレイリストの確認 <a class="header-anchor" href="#クライアントプレイリストの確認" aria-label="Permalink to “クライアントプレイリストの確認”">​</a></h2><p>プレイリストを作成したら、クライアントに確認してもらう準備ができたことを通知します。</p><p><img src="'+s+'" alt="グローバルプレイリスト"></p><p>::: 警告 クライアントはチームの一員である場合にのみ本番環境にアクセスでき、<strong>クライアントプレイリスト</strong>のみを表示できます。同じ本番環境内のクライアントを分ける方法はありませんのでご注意ください。 :::</p><p>クライアントはプレイリストを管理するためにいくつかのオプションがあります。</p><p>::: 危険 クライアントの権限</p><ul><li>クライアントはすべてのタスクタイプのすべてのバージョンを見ることができます。</li><li>クライアントは自身が投稿したコメントとそれらのコメントに対する返信のみを見ることができます。クライアントは内部コメントを見ることができません。</li><li>クライアントはリビジョンが公開された日時のみを見ることができますが、公開したユーザーを見ることはできません。</li><li>クライアントは<strong>「クライアントが許可されている」</strong>タグのステータスを見ることと使用することのみが可能です。 :::</li></ul><p><img src="'+e+'" alt="Playlist Review client"></p><p>クライアントは（左から右へ）以下の操作が可能です。</p><ul><li>ビデオの再生または一時停止。</li><li>1つの要素のループ再生。</li><li>LD（低解像度）とHD（高解像度）の切り替え。</li><li>再生速度の変更：2倍速（x2）、通常速（x1）、半分の速さ（x0.50）、4分の1の速さ（x0.25）。</li><li>再生中の注釈の表示。</li><li>音声のミュートまたはミュート解除。</li><li>音声の波形の表示。</li><li>プレイリスト内のすべての要素のタスクタイプの変更。</li><li>比較ツールの使用。</li><li>テキストおよび描画オプションの使用、選択した項目の削除。</li><li>コメントセクションを表示する。</li><li>プレイリストの要素を隠す。</li><li>プレイリストを、個別の要素すべてを含む<strong>Zip</strong>ファイル、<strong>.csv</strong>テキストファイル、または<strong>Build .mp4</strong>としてダウンロードし、ムービー全体を作成する（ショットのみ）。</li><li>フルスクリーン表示にする。</li></ul><p>::: ヒント クライアントは、キーボードの左右矢印を使用して、プレビューをフレームごとに移動することができます。 :::</p><p>また、クライアントは以下を行うことができます。</p><ul><li>要素をクリックして、要素から要素へと移動する。</li><li>全体の要素と比較した各要素の色と長さを見る。</li><li>全体の要素と比較した選択した要素の位置を緑色のドットで表示する。</li></ul><h2 id="再生コントロール" tabindex="-1">再生コントロール <a class="header-anchor" href="#再生コントロール" aria-label="Permalink to “再生コントロール”">​</a></h2><p>プレイリスト化されたショット/アセットごとに、クライアントは確認したい<strong>タスク</strong>と<strong>バージョン</strong>を選択することができます。</p><p><img src="'+o+'" alt="プレイリストのタスク選択"><img src="'+n+'" alt="プレイリストのバージョン選択"></p><p>また、[比較] ボタン <img src="'+_+'" alt="比較ボタン"> をクリックし、2番目のタスクタイプを選択することで、ショットの2つのタスクを並べて再生することもできます。</p><p><img src="'+c+'" alt="プレイリストの並列表示"></p><p>::: ヒント プレイリストの主な目的は、クライアントがショットとアセットを確認するのを支援することです。 プレビューから直接ショットにコメントを追加することができます。 :::</p><p>コメントを追加するには、<strong>コメント</strong>ボタンをクリックします。</p><p><img src="'+m+'" alt="プレイリストのコメント"></p><p>これにより右側のパネルが開き、コメントとステータスの履歴が表示されますが、内部コメントやステータスにはアクセスできません。</p><p><strong>描画</strong>ボタン <img src="'+g+'" alt="描画ボタン"> を使用して動画上に描画したり文字を入力したりしながら、同時にコメントを書き込むことができます。</p><p><img src="'+d+'" alt="プレイリストコメント"></p><p>描画されたコメントはビデオ上で確認できます（タイムラインの下の赤い点で示されています）。</p><p>::: 警告 クライアントのコメントはスーパーバイザーとプロダクションマネージャーのみが確認できます。アーティストはステータスのみ確認できます。</p><p>スーパーバイザーとプロダクションマネージャーはクライアントのコメントをコピーし、必要に応じて修正し、チームに公開することができます。</p><p><img src="'+h+'" alt="プレイリストのクライアントコメント"> :::</p><h2 id="レビュールーム" tabindex="-1">レビュールーム <a class="header-anchor" href="#レビュールーム" aria-label="Permalink to “レビュールーム”">​</a></h2><p>レビュールームは、効率的で同期されたデイリーズレビューセッションを行うために設計された共同作業スペースです。これにより、すべての参加者が同時に同じコンテンツを閲覧することができ、リアルタイムでのフィードバックやディスカッションが容易になります。</p><p><strong>レビュールーム</strong>に参加するには、プレイリストの上部にあるボタンをクリックします。レビュールームはすべての参加者を同期します。</p><p>レビュールーム内の全員が再生、一時停止、ショット、フレームの選択をリアルタイムで確認できます。</p><p>さらに、レビュールームでは同期描画注釈もサポートしています。この機能により、参加者はレビュー中のフレームに直接描画することができ、その注釈はセッション内の全員に表示されます。この機能により、コミュニケーションと明瞭性が向上し、特定の詳細の指摘、変更の提案、作品の重要な側面の強調が容易になります。</p><p><img src="'+x+'" alt="プレイリストレビュールーム"></p>',40)])])}const S=a(f,[["render",u]]);export{D as __pageData,S as default};
